function stripCredentials(url) {
    const parsedUrl = new URL(url);
    const { protocol, hostname, pathname, search, hash } = parsedUrl;

    // Remove username from the hostname
    const usernameIndex = hostname.indexOf('@');
    if (usernameIndex !== -1) {
        hostname = hostname.substring(usernameIndex + 1);
    }

    // Remove password from the hostname
    const passwordIndex = hostname.indexOf(':');
    if (passwordIndex !== -1) {
        hostname = hostname.substring(0, passwordIndex);
    }

    const strippedUrl = `${protocol}://${hostname}${pathname}${search}${hash}`;

